-- Quickly generate more deals with a simple loop-like approach
SELECT 
  gen_random_uuid(),
  (ARRAY(SELECT id FROM venues ORDER BY RANDOM() LIMIT 1))[1],
  'Happy Hour Deal #' || ROW_NUMBER() OVER (),
  'Limited time happy hour special.',
  (ARRAY['drink','food','combo','event'])[1 + (ROW_NUMBER() OVER () % 4)],
  (ARRAY['percentage','fixed','bogo','free','special'])[1 + (ROW_NUMBER() OVER () % 5)],
  (ARRAY[5, 10, 15, 20, 25])[1 + (ROW_NUMBER() OVER () % 5)],
  NULL,
  NULL,
  NOW(),
  NOW() + INTERVAL '1 day',
  true,
  false,
  100,
  ARRAY['happy_hour','deal']
FROM generate_series(1, 175);

